// ── Claude Vision API endpoint ────────────────────────────────────────────────
app.post('/api/analiz', async (req, res) => {
  const { imageBase64, mimeType, fileName } = req.body;

  if (!imageBase64) {
    return res.status(400).json({ error: 'Görsel verisi eksik' });
  }

  // 1. Dosya adından stok no kontrolü (hızlı yol)
  if (fileName) {
    for (const p of STOK) {
      if (fileName.includes(p.stokNo)) {
        return res.json({
          match: true,
          stokNo: p.stokNo,
          guven: 'Yüksek',
          pct: 98,
          aciklama: `${p.ad} — dosya adından stok numarası doğrulandı.`
        });
      }
    }
  }

  // 2. Claude Vision ile derin görsel analiz
  // Her parça için referans görsel + müşteri görseli yan yana gönder
  const contentBlocks = [];

  // Müşteri görseli
  contentBlocks.push({
    type: 'image',
    source: { type: 'base64', media_type: mimeType || 'image/jpeg', data: imageBase64 }
  });
  contentBlocks.push({
    type: 'text',
    text: 'Bu muşterinin gönderdigi parça görseli. Asagidaki referans görsellerle karşilaştir:'
  });

  // Her parça için referans görsel + açıklama
  for (const p of STOK) {
    const refImg = REF_IMAGES[p.stokNo];
    if (refImg) {
      const b64 = refImg.replace('data:image/jpeg;base64,', '');
      contentBlocks.push({ type: 'image', source: { type: 'base64', media_type: 'image/jpeg', data: b64 } });
    }
    contentBlocks.push({ type: 'text', text: `REFERANS - Stok No: ${p.stokNo} | ${p.ad} | ${p.gorselAciklama}` });
  }

  // Görev talimatı
  contentBlocks.push({
    type: 'text',
    text: `Görev: Müşteri görselindeki nesneyi referans görsellerle karşılaştır.\nKurallar:\n- Arka planı, cetveli, masayı yoksay, sadece nesneye bak\n- Farklı açı/ışık olabilir, forma ve detaylara odaklan\n- Hiçbiriyle %50 üzeri benzerlik yoksa veya yedek parça değilse match:false\nYanıtı SADECE JSON olarak ver: {"match": true/false, "stokNo": "XXXXXXXXXX veya null", "pct": 0-100, "aciklama": "kısa Türkçe açıklama"}`
  });

  try {
    const response = await client.messages.create({
      model: 'claude-opus-4-5',
      max_tokens: 300,
      messages: [{ role: 'user', content: contentBlocks }]
    });

    const raw = response.content[0].text.trim();
    console.log('[Claude yanıtı]', raw);

    // JSON parse
    const jsonMatch = raw.match(/\{[\s\S]*\}/);
    if (!jsonMatch) throw new Error('JSON bulunamadı: ' + raw);
    const result = JSON.parse(jsonMatch[0]);

    if (!result.match) {
      return res.json({ match: false, aciklama: result.aciklama || 'Eşleşme bulunamadı.' });
    }

    // Stok no doğrula
    const part = STOK.find(p => p.stokNo === result.stokNo);
    if (!part) {
      return res.json({ match: false, aciklama: 'Geçersiz stok no döndü.' });
    }

    const pct = Math.min(97, Math.max(50, result.pct || 75));
    res.json({
      match: true,
      stokNo: part.stokNo,
      guven: pct >= 82 ? 'Yüksek' : pct >= 65 ? 'Orta' : 'Düşük',
      pct,
      aciklama: result.aciklama || `${part.ad} — Claude Vision analizi.`
    });

  } catch (err) {
    console.error('[Hata]', err.message);
    res.status(500).json({ error: 'AI analizi başarısız: ' + err.message });
  }
});

// Health check
